VALUES
  ('elementary-f29af906-moex-00388', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關行政罰責任能力之敘述，依行政罰法之規定，下列何者錯誤？', '["未滿14歲人之行為，不予處罰", "14歲以上未滿16歲人之行為，得減輕處罰", "14歲以上未滿18歲人之行為，得減輕處罰", "行為時因精神障礙，致不能辨認其行為違法，不予處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00389', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關行政罰之法律適用，下列敘述何者錯誤？', '["違反行政法上義務之處罰，以行為時之法律或自治條例有明文規定者為限", "行為後法律有變更者，若變更前法律較有利於受處罰者，適用最有利受處罰者之法律", "行為後法律有變更者，適用最不利受處罰者之法律", "行為後法律有變更者，原則上適用最初裁處時之法律"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00390', 'elementary-f29af906', 'elementary-f29af906-moex-113-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '地政機關辦理所有權移轉登記計徵規費時，申請人如認有超收而發生爭執。下列敘述何者正確？', '["地政機關如依據土地公告現值，為合法計徵", "申請人如不服計徵方式，應提起民事訴訟請求返還", "申請人得依法以一般給付訴訟請求返還超收規費", "申請人應先提起確認訴訟確認是否超收"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "17c8e929e785", "answer_pdf_sha1": "120c8cc2fa96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00391', 'elementary-f29af906', 'elementary-f29af906-moex-112-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '一國面對景氣衰退時，政府往往會透過某些措施的採行，刺激景氣復甦，帶動經濟成長。下列何者無法 達成刺激景氣復甦的目標？', '["增加公共投資", "降低重貼現率", "獎勵民間投資", "取消補貼政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00392', 'elementary-f29af906', 'elementary-f29af906-moex-112-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '若世界僅由甲、乙兩國組成，且甲國生產所有商品的效率皆比乙國的水準高。若以機會成本的觀點而言， 下列有關甲、乙兩國生產及貿易的敘述，何者正確？', '["甲國生產所有商品均具絕對利益", "乙國向甲國進口所有產品最有利", "甲國生產所有商品的機會成本低於乙國", "若兩國進行分工，甲、乙兩國的生產可能線會內縮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00393', 'elementary-f29af906', 'elementary-f29af906-moex-112-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '大學剛畢業的小湘有三個工作機會與繼續升學的道路可選擇，一是月薪2萬5千元的家教老師；另一是 月薪2萬8千元的房屋仲介；以及月薪3萬元的法務助理；若選擇不就業，繼續進入研究所碩士班就讀， 學雜費兩年共需20萬元。依上述資料判斷，在不考慮其他條件的情況下，針對小湘大學畢業後兩年間做 選擇的機會成本之敘述，下列何者正確？', '["若當家教老師，機會成本為67萬2千元", "若選擇當房屋仲介，外顯成本為72萬元", "若選擇就學，外顯成本為72萬元", "若選擇就學，機會成本為92萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00394', 'elementary-f29af906', 'elementary-f29af906-moex-112-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '從塑化劑事件到毒澱粉，食安危機連環爆，連許多老店與大公司的知名產品都因使用有害人體健康的原 料，使消費者人人自危，深怕吃下肚的是黑心商品。許多產品銷售成績一落千丈，對加工食品業的業績 有負面影響。上述事件使消費者對加工食品需求的影響，下列何者正確？', '["預期加工食品價格會下跌，導致其需求曲線左移", "消費者對加工食品的偏好降低，導致其需求曲線左移", "加工食品的互補品價格下跌，導致加工食品的需求曲線右移", "天然食材製品的價格上漲，導致加工食品的需求曲線右移"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00395', 'elementary-f29af906', 'elementary-f29af906-moex-112-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '下列何種情況會使目前國產豬肉需求曲線往左移？', '["人口減少", "豬肉價格下降", "出現狂牛症疑慮", "行政院環境保護署嚴格取締養豬場對環境的污染"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00396', 'elementary-f29af906', 'elementary-f29af906-moex-112-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '甲、乙兩國均為已開發國家，甲國某年兩性同酬日為2個月又5天，乙國則為2個月又27天，顯示相較 於甲國，乙國受僱員工中女性要花費更多工作時間才能與男性同酬。根據上述，下列何種敘述或推測最 為可能？', '["乙國的性別職業隔離現象較甲國嚴重", "甲國制定的女性勞動政策較乙國友善", "兩國男性受高等教育的比例較女性多", "甲國的受僱者人均國民所得較乙國高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00397', 'elementary-f29af906', 'elementary-f29af906-moex-112-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '自強在半導體公司（甲）工作，平日擔任該公司的工會（乙）幹部，回到家裡（丙）是兩個孩子的爸爸， 假日時會帶小孩一起到兒福聯盟（丁）擔任志工，該團體是從事特殊際遇兒童保護工作的非營利組織， 關於前文所述，下列有關甲、乙、丙、丁的分析何者正確？', '["甲屬於《人民團體法》的職業團體", "乙屬於志願結社中的正式團體類型", "丙屬於成員間有職掌與編制的正式團體", "丁屬於私人機構獨立經營的「第二部門」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
